class Game:
    def __init__(self):
        self.board = Board()
        self.current_player = 'red'
        self.is_game_over = False

    def start(self):
        while not self.is_game_over:
            self.board.print_board()
            move = prompt_move(self.current_player)
            if validate_move(self.board, self.get_piece(move), move[0], move[1]):
                apply_move(self.board, self.get_piece(move), move[0], move[1])
                if check_winner(self.board):
                    print(f"{self.current_player.capitalize()} wins!")
                    self.is_game_over = True
                elif all(piece.is_kinged for piece in self.board.get_pieces()):
                    print("Draw by stalemate!")
                    self.is_game_over = True
                self.current_player = 'red' if self.current_player == 'black' else 'black'
            else:
                print("Invalid move. Try again.")

    def get_piece(self, move):
        start_pos = (ord(move[0]) - ord('A'), int(move[1]) - 1)
        return next((piece for piece in self.board.pieces if piece.position == start_pos), None)
