import random

class Board:
    def __init__(self):
        self.grid = [[None] * 8 for _ in range(8)]
        self.initialize_board()
        self.pieces = [piece for row in self.grid for piece in row if piece]

    def initialize_board(self):
        # Place initial pieces on the board
        for i, row in enumerate(self.grid):
            if i < 3:
                for j in range(0, 8, 2):
                    row[j] = Piece((i, j), 'red')
            elif i > 4:
                for j in range(1, 9, 2):
                    row[j - 1] = Piece((i, j - 1), 'black')

    def print_board(self):
        for row in self.grid:
            print(' '.join(['R' if piece and piece.color == 'red' else 'B' if piece and piece.color == 'black' else '-' for piece in row]))

    def get_pieces(self):
        return [piece for row in self.grid for piece in row if piece]
